import React, { useState, useRef, useCallback, useMemo } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, ScrollView, SafeAreaView, Image, Dimensions, Platform, Animated } from 'react-native';
import { useNavigation, useFocusEffect } from '@react-navigation/native';
import ScrollableGradientWrapper from '../components/ScrollableGradientWrapper';
import { getMetricPrices } from '../components/Prices/MetricPrices';
import BackButton from '../components/BackButton';

const { width: screenWidth } = Dimensions.get('window');
const MAX_COLUMN_WIDTH = Math.min(400, screenWidth * 0.45);
const BUTTON_WIDTH = Math.min(350, screenWidth * 0.4);
const isMobile = screenWidth < 800;

const adjustPrice = (basePrice, isOrderFittingMode) => {
  const price = parseFloat(basePrice.trim());
  return isOrderFittingMode ? (price * 0.8).toFixed(2) : price.toFixed(2);
};

const ShapeButton = ({ subtitle, imagePath, onPress, isSelected }) => (
  <TouchableOpacity 
    style={[styles.shapeButton, isSelected && styles.selectedShapeButton]} 
    onPress={onPress}
  >
    <View style={styles.shapeButtonContent}>
      <Text style={styles.shapeButtonSubtitle}>{subtitle}</Text>
    </View>
    {imagePath && (
      <View style={styles.shapeButtonImageContainer}>
        <Image source={imagePath} style={styles.shapeButtonImage} resizeMode="contain" />
      </View>
    )}
  </TouchableOpacity>
);

const SizeButton = ({ title, basePrice, isOrderFittingMode, onPress, isSelected }) => {
  const isMobileScreen = isMobile;
  const sizeButtonContentStyle = {
    flexDirection: isMobileScreen ? 'column' : 'row',
    justifyContent: 'center',
    alignItems: 'center',
  };
  const sizeTextContainerStyle = isMobileScreen ? { alignItems: 'center', marginBottom: 5 } : { flex: 1, marginRight: 10 };
  const priceBorderStyle = isMobileScreen ? { minWidth: null, width: '100%' } : { minWidth: 120 };
  
  const adjustedPrice = adjustPrice(basePrice.toString(), isOrderFittingMode);
  
  return (
    <TouchableOpacity 
      style={[styles.sizeButton, isSelected && styles.selectedSizeButton]} 
      onPress={onPress}
    >
      <View style={sizeButtonContentStyle}>
        <View style={[styles.sizeTextContainer, sizeTextContainerStyle]}>
          <Text style={styles.sizeButtonText}>{title}</Text>
        </View>
        <View style={[styles.priceBorder, priceBorderStyle, isSelected && styles.selectedPriceBorder]}>
          <Text style={[styles.priceText, isSelected && styles.selectedPriceText]}>
            A$ {adjustedPrice} ea
          </Text>
        </View>
      </View>
    </TouchableOpacity>
  );
};

const MetricFittingScreen1 = ({ route }) => {
  const navigation = useNavigation();
  const [selectedShape, setSelectedShape] = useState(null);
  const [selectedSize, setSelectedSize] = useState(null);
  const { selectedHose = null, selectedFitting = null, selectedHosePrice = null, isOrderFittingMode } = route.params;
  const contentFadeAnim = useRef(new Animated.Value(0)).current;

  // Get prices directly - no async needed
  const prices = getMetricPrices();

  const shapes = [
    { name: 'METRIC LIGHT Male Straight', image: require('../assets/metric_light_male_straight.png') },
    { name: 'METRIC LIGHT Female Straight', image: require('../assets/metric_light_female_straight.png') },
    { name: 'METRIC LIGHT Female 45°', image: require('../assets/metric_light_female_45.png') },
    { name: 'METRIC LIGHT Female 90°', image: require('../assets/metric_light_female_90.png') },
  ];

  // Define all available sizes with prices
  const allSizes = useMemo(() => [
    { size: 'M12 - 1.5', basePrice: `${prices["M12"]}` },
    { size: 'M14 - 1.5', basePrice: `${prices["M14"]}` },
    { size: 'M16 - 1.5', basePrice: `${prices["M16"]}` },
    { size: 'M18 - 1.5', basePrice: `${prices["M18"]}` },
    { size: 'M22 - 1.5', basePrice: `${prices["M22"]}` },
    { size: 'M26 - 1.5', basePrice: `${prices["M26"]}` },
    { size: 'M30 - 2', basePrice: `${prices["M30"]}` },
    { size: 'M36 - 2', basePrice: `${prices["M36"]}` }
  ], [prices]);

  // Define the Metric compatibility matrix
  const compatibilityMatrix = {
    '1/4"': ['M12', 'M14', 'M16', 'M18'],
    '3/8"': ['M18', 'M22'],
    '1/2"': ['M22', 'M26'],
    '5/8"': ['M26', 'M30'],
    '3/4"': ['M30', 'M36'],
    '1"': ['M36']
  };

  // Function to filter sizes based on selected hose size
  const getFilteredSizes = () => {
    if (!selectedHose || !selectedHose.size) {
      return allSizes;
    }
    
    const hoseSize = selectedHose.size;
    const compatibleSizes = compatibilityMatrix[hoseSize] || [];
    
    return allSizes.filter(sizeObj => 
      compatibleSizes.includes(sizeObj.size.split(' ')[0])
    );
  };

  const sizes = getFilteredSizes();

  useFocusEffect(
    useCallback(() => {
      Animated.timing(contentFadeAnim, {
        toValue: 1,
        duration: 500,
        useNativeDriver: Platform.OS !== 'web',
      }).start();
  
      return () => {
        contentFadeAnim.setValue(0);
      };
    }, [contentFadeAnim])
  );

  const handleShapeSelection = (shape) => {
    setSelectedShape(shape);
    setSelectedSize(null);
  };

  const handleSizeSelection = (size) => {
    setSelectedSize(size);
    if (selectedShape && size) {
      const selectedSizeObj = sizes.find(sizeObj => sizeObj.size === size);
      const adjustedPrice = parseFloat(adjustPrice(selectedSizeObj.basePrice.toString(), isOrderFittingMode));
      handleNavigation(selectedShape, size, adjustedPrice);
    }
  };
  
  const handleNavigation = (shape, size, price) => {
    Animated.timing(contentFadeAnim, {
      toValue: 0,
      duration: 500,
      useNativeDriver: Platform.OS !== 'web',
    }).start(() => {
      if (isOrderFittingMode) {
        navigation.navigate('CutLengths', {
          selectedHose: null,
          selectedHosePrice: null,
          selectedFitting: selectedFitting || null,
          end1Shape: shape,
          end1Size: size,
          end1Price: price,
          selectedEnd2Fitting: null,
          end2Shape: null,
          end2Size: null,
          end2Price: null,
          selectedAngle: null,
          isHoseOnly: false,
          isOrderFittingMode: true
        });
      } else {
        navigation.navigate('End2Fitting', {
          selectedHose,
          selectedHosePrice,
          selectedFitting,
          end1Shape: shape,
          end1Size: size,
          end1Price: price
        });
      }
    });
  };

  return (
    <Animated.View style={[styles.mainContainer, { opacity: contentFadeAnim }]}>
      <BackButton onPress={() => navigation.goBack()} />
      
      <ScrollableGradientWrapper>
        <SafeAreaView style={styles.container}>
          <View style={styles.logoContainer}>
            <Image
              source={require('../assets/fluidpower_logo.gif')}
              style={styles.logo}
              resizeMode="contain"
            />
          </View>
          
          <Animated.View style={[styles.animatedContainer, { opacity: contentFadeAnim }]}>
            <View style={styles.titleContainer}>
              <View style={styles.titleWrapper}>
                {isOrderFittingMode ? (
                  <Text style={styles.titleText}>Thread Shape and Size</Text>
                ) : (
                  <>
                    <Text style={styles.titleText}>Select END </Text>
                    <View style={styles.circleWrapper}>
                      <Text style={styles.circleText}>1</Text>
                    </View>
                    <Text style={styles.titleText}> Thread</Text>
                  </>
                )}
              </View>
            </View>
            
            <View style={styles.contentContainer}>
              <View style={styles.column}>
                <View style={styles.sectionTitleContainer}>
                  <Text style={styles.sectionTitleText}>Select SHAPE</Text>
                </View>
                <ScrollView 
                  contentContainerStyle={styles.scrollViewContent}
                  style={styles.scrollView}
                  showsVerticalScrollIndicator={false}
                >
                  {shapes.map((shape, index) => (
                    <ShapeButton
                      key={index}
                      subtitle={shape.name}
                      imagePath={shape.image}
                      onPress={() => handleShapeSelection(shape.name)}
                      isSelected={selectedShape === shape.name}
                    />
                  ))}
                </ScrollView>
              </View>
              
              <View style={styles.column}>
                {selectedShape ? (
                  <>
                    <View style={styles.sectionTitleContainer}>
                      <Text style={styles.sectionTitleText}>Select SIZE</Text>
                    </View>
                    <Text style={styles.sectionSubtitle}>Size - Thread Pitch</Text>
                    <ScrollView 
                      contentContainerStyle={styles.scrollViewContent}
                      style={styles.scrollView}
                      showsVerticalScrollIndicator={false}
                    >
                      {sizes.map((size, index) => (
                        <SizeButton
                          key={index}
                          title={size.size}
                          basePrice={size.basePrice}
                          isOrderFittingMode={isOrderFittingMode}
                          onPress={() => handleSizeSelection(size.size)}
                          isSelected={selectedSize === size.size}
                        />
                      ))}
        
                      {isOrderFittingMode && (
                        <>
                          <View style={styles.ferruleContainer}>
                            <Image
                              source={require('../assets/Ferrule.PNG')}
                              style={styles.ferruleImage}
                              resizeMode="contain"
                            />
                          </View>
                          <View style={styles.ferruleTextContainer}>
                            <Text style={styles.ferruleText}>
                              Price Inclusive of Ferrule
                            </Text>
                          </View>
                        </>
                      )}
                    </ScrollView>
                  </>
                ) : (
                  <View style={styles.placeholderColumn} />
                )}
              </View>
            </View>
            
            <View style={styles.fittingTypeContainer}>
              <Text style={styles.fittingTypeText}>METRIC LIGHT 24° (O-Ring Cone)</Text>
            </View>
          </Animated.View>
        </SafeAreaView>
      </ScrollableGradientWrapper>
    </Animated.View>
  );
};

